        $systemParams['accessToken'] = $this->config->getAccessToken();
        $timestamp = (string)(time() * 1000); // ��ȡ��ǰʱ��������룩
        $systemParams['timestamp'] = $timestamp;

        // ����ǩ��
        $signMap = SignatureCalculator::parameterConvert($systemParams, $queryParams, $httpBody, $pathParams);
        $sign = SignatureCalculator::calculateSignature($this->config->getAppSecret(), $signMap);

        // ����ϵͳͷ��
        $headerParams["X-JOS-Sign"] =  $sign;
        $headerParams["X-JOS-Timestamp"] = $timestamp;
        $headerParams["X-JOS-App-Key"] = $this->config->getAppKey();
        $headerParams["X-JOS-Access-Token"] = $this->config->getAccessToken();
        $headerParams["X-JOS-Sdk-Version"] = "php-v2";

        $headers = array_merge(
            $defaultHeaders,
            $headerParams,
            $headers
        );
        return new Request(
            'POST',
            $operationHost . $resourcePath . ($query ? "?{$query}" : ''),
            $headers,
            $httpBody
        );
    }

    /**
     * Create http client option
     *
     * @throws \RuntimeException on file opening failure
     * @return array of http client options
     */
    protected function createHttpClientOption()
    {
        $options = [];
        if ($this->config->getDebug()) {
            $options[RequestOptions::DEBUG] = fopen($this->config->getDebugFile(), 'a');
            if (!$options[RequestOptions::DEBUG]) {
                throw new \RuntimeException('Failed to open the debug file: ' . $this->config->getDebugFile());
            }
        }

        return $options;
    }
}
